/** @odoo-module alias=buz_pos_core.ProductScreen **/
import { ProductScreen } from "@point_of_sale/app/screens/product_screen/product_screen";
import { patch } from "@odoo/owl";
import { usePos } from "@point_of_sale/app/store/pos_hook";
import { onMounted } from "@odoo/owl";

patch(ProductScreen.prototype, {
    setup() {
        super.setup(...arguments);
        this.pos = usePos();
        onMounted(() => {
            this._buzFocusSearch();
        });
    },

    _buzFocusSearch() {
        const searchInput = document.querySelector('.pos-search-bar input');
        if (searchInput) {
            searchInput.focus();
        }
    },

    get buzConfig() {
        return this.pos.config || {};
    },

    get buzShowStock() {
        return this.buzConfig.buz_show_stock_in_pos;
    },

    get buzCategories() {
        const categories = this.pos.records["pos.category"] || {};
        return Object.values(categories).sort((a, b) =>
            (a.parent_id || 0) - (b.parent_id || 0)
        );
    },

    buzGetProductStock(product) {
        if (!this.buzShowStock) return null;
        const qtyAvailable = product.qty_available || 0;
        return qtyAvailable;
    },

    buzQuickAddProduct(product) {
        const order = this.pos.get_order();
        if (!order) return;
        order.add_product(product, { quantity: 1 });
    },

    buzSetOrderNote(note) {
        const order = this.pos.get_order();
        if (order) {
            order.buz_order_note = note;
        }
    },

    buzSetDelivery(isDelivery) {
        const order = this.pos.get_order();
        if (order) {
            order.buz_is_delivery = isDelivery;
        }
    },

    buzSetSource(source) {
        const order = this.pos.get_order();
        if (order) {
            order.buz_source = source;
        }
    },
});

/** @odoo-module alias=buz_pos_core.PaymentScreen **/
import { PaymentScreen } from "@point_of_sale/app/screens/payment_screen/payment_screen";
import { patch } from "@odoo/owl";
import { usePos } from "@point_of_sale/app/store/pos_hook";

patch(PaymentScreen.prototype, {
    setup() {
        super.setup(...arguments);
        this.pos = usePos();
    },

    get buzEnableMultiPayment() {
        return this.pos.config.buz_enable_multi_payment;
    },

    get buzOrderNote() {
        const order = this.pos.get_order();
        return order ? order.buz_order_note : '';
    },

    get buzIsDelivery() {
        const order = this.pos.get_order();
        return order ? order.buz_is_delivery : false;
    },

    buzAddPaymentLine(paymentMethod, amount) {
        const order = this.pos.get_order();
        if (!order) return;
        order.add_paymentline(paymentMethod);
        const line = order.selected_paymentline;
        if (line && amount) {
            line.set_amount(amount);
        }
    },

    buzValidatePayment() {
        const order = this.pos.get_order();
        if (!order) return false;

        const total = order.get_total_with_tax();
        const paid = order.get_total_paid();
        const remaining = total - paid;

        if (remaining > 0.01) {
            return false;
        }
        return true;
    },

    async buzFinalizeOrder() {
        if (!this.buzValidatePayment()) {
            return;
        }
        await this.validateOrder();
    },
});

/** @odoo-module alias=buz_pos_core.ReceiptScreen **/
import { ReceiptScreen } from "@point_of_sale/app/screens/receipt_screen/receipt_screen";
import { patch } from "@odoo/owl";
import { usePos } from "@point_of_sale/app/store/pos_hook";

patch(ReceiptScreen.prototype, {
    setup() {
        super.setup(...arguments);
        this.pos = usePos();
    },

    get buzReceiptConfig() {
        return {
            showQr: this.pos.config.buz_receipt_show_qr,
            promptpayId: this.pos.config.buz_promptpay_id,
            footer: this.pos.config.buz_receipt_footer,
        };
    },

    get buzOrderData() {
        const order = this.pos.get_order();
        if (!order) return {};
        return {
            note: order.buz_order_note,
            isDelivery: order.buz_is_delivery,
            deliveryAddress: order.buz_delivery_address,
            deliveryPhone: order.buz_delivery_phone,
            source: order.buz_source,
        };
    },

    buzGeneratePromptPayPayload(amount) {
        const ppId = this.pos.config.buz_promptpay_id;
        if (!ppId) return null;

        // PromptPay QR: EMVCo format (simplified)
        const idType = ppId.length >= 13 ? 'A' : 'M';
        const amountStr = amount.toFixed(2);
        return {
            ppId,
            idType,
            amount: amountStr,
        };
    },
});

/** @odoo-module alias=buz_pos_core.OrderWidget **/
import { OrderWidget } from "@point_of_sale/app/generic_components/order_widget/order_widget";
import { patch } from "@odoo/owl";

patch(OrderWidget.prototype, {
    get buzLineNotes() {
        const order = this.env.services.pos.get_order();
        if (!order) return {};
        const notes = {};
        for (const line of order.get_orderlines()) {
            if (line.buz_line_note) {
                notes[line.id] = line.buz_line_note;
            }
        }
        return notes;
    },

    get buzOrderNote() {
        const order = this.env.services.pos.get_order();
        return order ? order.buz_order_note : '';
    },

    buzSetLineNote(line, note) {
        line.buz_line_note = note;
        line.trigger('change', line);
    },

    buzSetLineDiscount(line, discount, reason) {
        line.set_discount(discount);
        line.buz_line_discount_reason = reason;
    },
});

