// Extend Order with Buz POS fields
patch(Order.prototype, {
    buz_order_note: '',
    buz_delivery_address: '',
    buz_delivery_phone: '',
    buz_delivery_date: null,
    buz_is_delivery: false,
    buz_delivery_driver_id: null,
    buz_delivery_status: 'pending',
    buz_source: 'walk_in',

    export_as_JSON() {
        const json = super.export_as_JSON(...arguments);
        json.buz_order_note = this.buz_order_note;
        json.buz_delivery_address = this.buz_delivery_address;
        json.buz_delivery_phone = this.buz_delivery_phone;
        json.buz_delivery_date = this.buz_delivery_date;
        json.buz_is_delivery = this.buz_is_delivery;
        json.buz_delivery_driver_id = this.buz_delivery_driver_id;
        json.buz_delivery_status = this.buz_delivery_status;
        json.buz_source = this.buz_source;
        return json;
    },

    init_from_JSON(json) {
        super.init_from_JSON(...arguments);
        this.buz_order_note = json.buz_order_note || '';
        this.buz_delivery_address = json.buz_delivery_address || '';
        this.buz_delivery_phone = json.buz_delivery_phone || '';
        this.buz_delivery_date = json.buz_delivery_date || null;
        this.buz_is_delivery = json.buz_is_delivery || false;
        this.buz_delivery_driver_id = json.buz_delivery_driver_id || null;
        this.buz_delivery_status = json.buz_delivery_status || 'pending';
        this.buz_source = json.buz_source || 'walk_in';
    },
});

// Extend Orderline with Buz POS fields
patch(Orderline.prototype, {
    buz_line_note: '',
    buz_line_discount_reason: '',

    export_as_JSON() {
        const json = super.export_as_JSON(...arguments);
        json.buz_line_note = this.buz_line_note;
        json.buz_line_discount_reason = this.buz_line_discount_reason;
        return json;
    },

    init_from_JSON(json) {
        super.init_from_JSON(...arguments);
        this.buz_line_note = json.buz_line_note || '';
        this.buz_line_discount_reason = json.buz_line_discount_reason || '';
    },
});

