from odoo import api, fields, models


class PosOrder(models.Model):
    _inherit = 'pos.order'

    buz_delivery_order_id = fields.Many2one(
        'buz.delivery.order', string='Delivery Order',
    )

    def _create_order_picking(self):
        """Override to create delivery order when POS order has delivery."""
        result = super()._create_order_picking()
        for order in self.filtered(lambda o: o.buz_is_delivery):
            if not order.buz_delivery_order_id:
                delivery_vals = {
                    'pos_order_id': order.id,
                    'partner_id': order.partner_id.id if order.partner_id else False,
                    'delivery_address': order.buz_delivery_address or '',
                    'delivery_phone': order.buz_delivery_phone or '',
                    'scheduled_date': order.buz_delivery_date or fields.Datetime.now(),
                    'note': order.buz_order_note or '',
                }
                delivery_order = self.env['buz.delivery.order'].sudo().create(delivery_vals)
                order.buz_delivery_order_id = delivery_order.id
        return result

/** @odoo-module alias=buz_pos_delivery.DeliveryScreen **/
import { AbstractAwaitablePopup } from "@point_of_sale/app/popup/abstract_awaitable_popup";
import { patch } from "@odoo/owl";
import { usePos } from "@point_of_sale/app/store/pos_hook";
import { useState } from "@odoo/owl";

export class DeliveryPopup extends AbstractAwaitablePopup {
    static template = "buz_pos_delivery.DeliveryPopup";

    setup() {
        super.setup();
        this.pos = usePos();
        this.state = useState({
            address: '',
            phone: '',
            zoneId: null,
            driverId: null,
            scheduledDate: '',
            note: '',
        });
    }

    get zones() {
        return this.pos.config.buz_delivery_zone_ids || [];
    }

    get availableDrivers() {
        // Filter drivers by availability
        return [];
    }

    get deliveryFee() {
        if (!this.state.zoneId) return 0;
        const zone = this.zones.find(z => z.id === this.state.zoneId);
        if (!zone) return 0;

        const order = this.pos.get_order();
        const total = order ? order.get_total_with_tax() : 0;

        if (zone.min_order_amount > 0 && total >= zone.min_order_amount) {
            return 0;
        }
        return zone.delivery_fee;
    }

    confirm() {
        const order = this.pos.get_order();
        if (order) {
            order.buz_is_delivery = true;
            order.buz_delivery_address = this.state.address;
            order.buz_delivery_phone = this.state.phone;
            order.buz_delivery_date = this.state.scheduledDate || null;
            order.buz_order_note = this.state.note;

            // Add delivery fee line if applicable
            if (this.deliveryFee > 0 && this.pos.config.buz_delivery_product_id) {
                const deliveryProduct = this.pos.config.buz_delivery_product_id;
                order.add_product(deliveryProduct, {
                    quantity: 1,
                    price: this.deliveryFee,
                });
            }
        }
        super.confirm();
    }
}

