from odoo import fields, models


class PosOrder(models.Model):
    _inherit = 'pos.order'

    buz_promotion_rule_ids = fields.Many2many(
        'buz.promotion.rule', string='Applied Promotions',
    )
    buz_coupon_id = fields.Many2one(
        'buz.promotion.coupon', string='Coupon',
    )
    buz_total_discount_promotion = fields.Float(
        string='Promotion Discount', compute='_compute_promotion_discount',
    )

    def _compute_promotion_discount(self):
        for order in self:
            discount = 0.0
            for line in order.lines:
                if line.buz_line_discount_reason == 'promotion':
                    discount += line.qty * line.price_unit * (line.discount / 100)
            order.buz_total_discount_promotion = discount

/** @odoo-module alias=buz_pos_promotion.PromotionPopup **/
import { AbstractAwaitablePopup } from "@point_of_sale/app/popup/abstract_awaitable_popup";
import { useState } from "@odoo/owl";

export class PromotionPopup extends AbstractAwaitablePopup {
    static template = "buz_pos_promotion.PromotionPopup";

    setup() {
        super.setup();
        this.state = useState({
            couponCode: '',
            message: '',
            messageType: '',
        });
    }

    async applyCoupon() {
        if (!this.state.couponCode) {
            this.state.message = 'กรุณาใส่รหัสคูปอง';
            this.state.messageType = 'error';
            return;
        }
        // Trigger coupon validation via RPC
        try {
            const result = await this.env.services.orm.call(
                'buz.promotion.coupon',
                'search_read',
                [[['name', '=', this.state.couponCode], ['state', '=', 'active']]],
                ['name', 'rule_id', 'max_use', 'use_count', 'expiry_date'],
                { limit: 1 },
            );
            if (result.length === 0) {
                this.state.message = 'คูปองไม่ถูกต้องหรือหมดอายุ';
                this.state.messageType = 'error';
                return;
            }
            const coupon = result[0];
            if (coupon.use_count >= coupon.max_use) {
                this.state.message = 'คูปองถูกใช้ครบจำนวนแล้ว';
                this.state.messageType = 'error';
                return;
            }
            this.state.message = `ใช้คูปอง "${coupon.name}" สำเร็จ!`;
            this.state.messageType = 'success';
        } catch (e) {
            this.state.message = 'เกิดข้อผิดพลาด';
            this.state.messageType = 'error';
        }
    }

    confirm() {
        super.confirm();
    }
}

/** @odoo-module alias=buz_pos_promotion.PromotionEngine **/
import { ProductScreen } from "@point_of_sale/app/screens/product_screen/product_screen";
import { patch } from "@odoo/owl";
import { usePos } from "@point_of_sale/app/store/pos_hook";
import { PromotionPopup } from "./PromotionPopup.js";

patch(ProductScreen.prototype, {
    setup() {
        super.setup(...arguments);
        this.pos = usePos();
    },

    buzOpenPromotionPopup() {
        this.pos.popup.add(PromotionPopup, {
            title: 'Promotions & Coupons',
        });
    },

    async buzCheckAutoPromotions() {
        const order = this.pos.get_order();
        if (!order) return;

        const promotions = this.pos.records['buz.promotion.rule'] || {};
        const applicable = Object.values(promotions).filter(
            p => p.auto_apply && p.active
        );

        for (const promo of applicable) {
            if (promo.min_order_amount > 0) {
                const total = order.get_total_with_tax();
                if (total < promo.min_order_amount) continue;
            }
            // Apply discount
            if (promo.rule_type === 'discount_percent' && promo.discount_percent > 0) {
                for (const line of order.get_orderlines()) {
                    line.set_discount(promo.discount_percent);
                    line.buz_line_discount_reason = 'promotion';
                }
            }
        }
    },
});

