from odoo import api, fields, models


class LoyaltyTier(models.Model):
    _name = 'buz.loyalty.tier'
    _description = 'Loyalty Tier'
    _order = 'min_points'

    name = fields.Char(string='Tier Name', required=True)
    company_id = fields.Many2one(
        'res.company', default=lambda self: self.env.company,
    )
    active = fields.Boolean(default=True)
    sequence = fields.Integer(default=10)
    min_points = fields.Integer(
        string='Min Points', required=True,
        help='Minimum accumulated points to reach this tier',
    )
    points_per_baht = fields.Float(
        string='Points per ฿', default=1.0,
        help='Points earned per 1 THB spent',
    )
    discount_percent = fields.Float(
        string='Default Discount %', default=0.0,
        help='Automatic discount for customers at this tier',
