class LoyaltyCard(models.Model):
    _name = 'buz.loyalty.card'
    _description = 'Loyalty Card'
    _inherit = ['mail.thread', 'mail.activity.mixin']

    name = fields.Char(
        string='Card Number', required=True, readonly=True,
        default=lambda self: self.env['ir.sequence'].next_by_code('buz.loyalty.card') or 'New',
    )
    partner_id = fields.Many2one(
        'res.partner', string='Customer', required=True, tracking=True,
    )
    company_id = fields.Many2one(
        'res.company', default=lambda self: self.env.company,
    )
    tier_id = fields.Many2one(
        'buz.loyalty.tier', string='Current Tier',
        compute='_compute_tier', store=True,
    )
    total_points = fields.Integer(
        string='Total Points', default=0, tracking=True,
    )
    available_points = fields.Integer(
        string='Available Points', default=0,
    )
    transaction_ids = fields.One2many(
        'buz.loyalty.transaction', 'card_id', string='Transactions',
    )
    total_spent = fields.Float(
        string='Total Spent', default=0.0,
    )
    join_date = fields.Date(
        string='Join Date', default=fields.Date.today,
    )
    last_activity = fields.Date(
        string='Last Activity', compute='_compute_last_activity',
    )
    state = fields.Selection([
        ('active', 'Active'),
        ('suspended', 'Suspended'),
        ('expired', 'Expired'),
    ], default='active', string='Status')

    @api.depends('total_points')
    def _compute_tier(self):
        Tier = self.env['buz.loyalty.tier']
        for card in self:
            tiers = Tier.search([
                ('company_id', '=', card.company_id.id),
            ], order='min_points desc')
            card.tier_id = False
            for tier in tiers:
                if card.total_points >= tier.min_points:
                    card.tier_id = tier.id
                    break

    def _compute_last_activity(self):
        Transaction = self.env['buz.loyalty.transaction']
        for card in self:
            last = Transaction.search([
                ('card_id', '=', card.id),
            ], order='create_date desc', limit=1)
            card.last_activity = last.create_date.date() if last else False

    @api.model_create_multi
    def create(self, vals_list):
        for vals in vals_list:
            if vals.get('name', 'New') == 'New':
                vals['name'] = self.env['ir.sequence'].next_by_code(
                    'buz.loyalty.card'
                ) or 'New'
        return super().create(vals_list)

    def add_points(self, points, order_id=None, description=''):
        self.ensure_one()
        self.total_points += points
        self.available_points += points
        self.env['buz.loyalty.transaction'].create({
            'card_id': self.id,
            'type': 'earn',
            'points': points,
            'pos_order_id': order_id,
            'description': description or f'Earned {points} points',
        })

    def redeem_points(self, points, order_id=None, description=''):
        self.ensure_one()
        if points > self.available_points:
            return False
        self.available_points -= points
        self.env['buz.loyalty.transaction'].create({
            'card_id': self.id,
            'type': 'redeem',
            'points': -points,
            'pos_order_id': order_id,
            'description': description or f'Redeemed {points} points',
        })
        return True


