patch(ProductScreen.prototype, {
    buzQuickSearchSetup() {
        this.buzSearchState = useState({
            query: '',
            results: [],
        });
    },

    buzOnSearchInput(ev) {
        const query = ev.target.value.trim();
        this.buzSearchState.query = query;
        if (!query || query.length < 2) {
            this.buzSearchState.results = [];
            return;
        }
        const products = this.pos.records["product.product"] || {};
        const lowerQuery = query.toLowerCase();
        this.buzSearchState.results = Object.values(products)
            .filter(p =>
                p.display_name?.toLowerCase().includes(lowerQuery) ||
                p.barcode?.includes(query) ||
                p.default_code?.toLowerCase().includes(lowerQuery)
            )
            .slice(0, 12);
    },

    buzQuickAdd(product) {
        const order = this.pos.get_order();
        if (order && product) {
            order.add_product(product, { quantity: 1 });
        }
        this.buzSearchState.query = '';
        this.buzSearchState.results = [];
    },
});

