from odoo import fields, models


class ReportProductRanking(models.AbstractModel):
    _name = 'report.buz_pos_reports.product_ranking'
    _description = 'Product Ranking Report'

    def _get_report_values(self, docids, data=None):
        session = self.env['pos.session'].browse(docids)
        orders = self.env['pos.order'].search([
            ('session_id', '=', session.id),
            ('state', 'in', ['paid', 'done', 'invoiced']),
        ])

        product_sales = {}
        for order in orders:
            for line in order.lines:
                pid = line.product_id.id
                if pid not in product_sales:
                    product_sales[pid] = {
                        'name': line.product_id.name,
                        'category': line.product_id.pos_categ_id.name or '-',
                        'qty': 0,
                        'revenue': 0,
                        'orders': 0,
                    }
                product_sales[pid]['qty'] += line.qty
                product_sales[pid]['revenue'] += line.price_subtotal_incl
                product_sales[pid]['orders'] += 1

        # Sort by revenue
        by_revenue = sorted(
            product_sales.values(), key=lambda x: x['revenue'], reverse=True
        )
        # Sort by qty
        by_qty = sorted(
            product_sales.values(), key=lambda x: x['qty'], reverse=True
        )

        return {
            'doc_ids': docids,
            'doc_model': 'pos.session',
            'docs': session,
            'by_revenue': by_revenue[:30],
            'by_qty': by_qty[:30],
        }

