import logging
import requests
from odoo import api, fields, models

_logger = logging.getLogger(__name__)


class PosOrder(models.Model):
    _inherit = 'pos.order'

    def _create_order_picking(self):
        result = super()._create_order_picking()
        for order in self:
            order._buz_send_line_notification('new_order')
        return result

    def _buz_send_line_notification(self, event_type):
        """Send LINE Notify message."""
        config = self.config_id
        token = config.buz_line_notify_token
        if not token:
            return

        messages = {
            'new_order': (
                f"🛒 ออเดอร์ใหม่!\n"
                f"Order: {self.name}\n"
                f"ยอดรวม: {self.amount_total:,.2f} ฿\n"
                f"ลูกค้า: {self.partner_id.name or 'Walk-in'}\n"
                f"ช่องทาง: {self.buz_source or '-'}"
            ),
            'delivery': (
                f"🚗 กำลังจัดส่ง!\n"
                f"Order: {self.name}\n"
                f"ที่อยู่: {self.buz_delivery_address}\n"
                f"โทร: {self.buz_delivery_phone}"
            ),
        }

        message = messages.get(event_type)
        if not message:
            return

        # Check event-specific notification settings
        if event_type == 'new_order' and not config.buz_line_notify_on_order:
            return
        if event_type == 'delivery' and not config.buz_line_notify_on_delivery:
            return

        try:
            requests.post(
                'https://notify-api.line.me/api/notify',
                headers={'Authorization': f'Bearer {token}'},
                data={'message': message},
                timeout=5,
            )
            _logger.info('LINE Notify sent for order %s event %s', self.name, event_type)
        except Exception as e:
            _logger.warning('LINE Notify failed: %s', str(e))

    def action_buz_notify_delivery(self):
        """Manual trigger for delivery notification."""
        self.ensure_one()
        self._buz_send_line_notification('delivery')
        return {'type': 'ir.actions.act_window_close'}

/** @odoo-module alias=buz_pos_integration.ESCPOS **/
import { ReceiptScreen } from "@point_of_sale/app/screens/receipt_screen/receipt_screen";
import { patch } from "@odoo/owl";

patch(ReceiptScreen.prototype, {
    /**
     * Print receipt to ESC/POS thermal printer via network.
     * Uses the printer IP configured in POS settings.
     */
    async buzPrintESCPOS() {
        const config = this.env.services.pos.config;
        const printerIp = config.buz_escpos_printer_ip;
        const printerPort = config.buz_escpos_printer_port || 9100;

        if (!printerIp) {
            console.warn('[Buz POS] No ESC/POS printer IP configured');
            return false;
        }

        const order = this.env.services.pos.get_order();
        if (!order) return false;

        // Build ESC/POS commands
        const commands = this._buzBuildESCPOSCommands(order, config);

        try {
            // Send to printer via WebSocket proxy or direct TCP
            // Note: Direct TCP from browser requires a proxy service
            const response = await fetch(
                `http://${printerIp}:${printerPort}`,
                {
                    method: 'POST',
                    body: commands,
                    mode: 'no-cors',
                }
            );
            console.info('[Buz POS] Receipt sent to ESC/POS printer');
            return true;
        } catch (err) {
            console.error('[Buz POS] ESC/POS print failed:', err);
            return false;
        }
    },

    _buzBuildESCPOSCommands(order, config) {
        const ESC = '\x1B';
        const GS = '\x1D';
        const LF = '\x0A';
        const paperWidth = config.buz_escpos_paper_width === '58' ? 32 : 48;

        let cmd = '';
        // Initialize printer
        cmd += ESC + '@';
        // Center align
        cmd += ESC + 'a' + '\x01';
        // Company name (would come from config)
        cmd += '*** BUZ POS ***' + LF + LF;
        // Left align
        cmd += ESC + 'a' + '\x00';
        // Order info
        cmd += `Order: ${order.name || ''}${LF}`;
        cmd += `Date: ${new Date().toLocaleString('th-TH')}${LF}`;
        cmd += '--------------------------------' + LF;

        // Order lines
        for (const line of order.get_orderlines()) {
            const name = line.full_product_name?.substring(0, 20) || '';
            const qty = line.quantity;
            const price = (line.price * qty).toFixed(2);
            cmd += `${name}${LF}`;
            cmd += `  ${qty} x ${line.price.toFixed(2)}  = ${price}${LF}`;
        }

        cmd += '--------------------------------' + LF;
        // Totals
        cmd += `Subtotal: ${order.get_total_without_tax().toFixed(2)}${LF}`;
        cmd += `Tax: ${order.get_total_tax().toFixed(2)}${LF}`;
        cmd += ESC + 'E' + '\x01'; // Bold on
        cmd += `TOTAL: ${order.get_total_with_tax().toFixed(2)} THB${LF}`;
        cmd += ESC + 'E' + '\x00'; // Bold off
        cmd += '--------------------------------' + LF;

        // Footer
        if (config.buz_receipt_footer) {
            cmd += LF + config.buz_receipt_footer + LF;
        }

        // Cut paper
        cmd += LF + LF + LF;
        cmd += GS + 'V' + '\x00';

        return cmd;
    },
});

/** @odoo-module alias=buz_pos_integration.BarcodeHandler **/
import { ProductScreen } from "@point_of_sale/app/screens/product_screen/product_screen";
import { patch } from "@odoo/owl";
import { onMounted, onWillUnmount } from "@odoo/owl";

patch(ProductScreen.prototype, {
    setup() {
        super.setup(...arguments);
        onMounted(() => {
            this._buzStartBarcodeListener();
        });
        onWillUnmount(() => {
            this._buzStopBarcodeListener();
        });
    },

    _buzStartBarcodeListener() {
        this._buzBarcodeBuffer = '';
        this._buzBarcodeTimeout = null;
        this._buzBarcodeHandler = (ev) => this._buzOnBarcodeKey(ev);
        document.addEventListener('keydown', this._buzBarcodeHandler);
    },

    _buzStopBarcodeListener() {
        if (this._buzBarcodeHandler) {
            document.removeEventListener('keydown', this._buzBarcodeHandler);
        }
    },

    _buzOnBarcodeKey(ev) {
        // Barcode scanners typically send characters quickly followed by Enter
        if (ev.key === 'Enter' && this._buzBarcodeBuffer.length >= 4) {
            const barcode = this._buzBarcodeBuffer;
            this._buzBarcodeBuffer = '';
            clearTimeout(this._buzBarcodeTimeout);

            // Search product by barcode
            this._buzHandleBarcode(barcode);
            ev.preventDefault();
            return;
        }

        if (ev.key.length === 1) {
            this._buzBarcodeBuffer += ev.key;
            clearTimeout(this._buzBarcodeTimeout);
            this._buzBarcodeTimeout = setTimeout(() => {
                this._buzBarcodeBuffer = '';
            }, 100); // Reset buffer after 100ms of no input
        }
    },

    _buzHandleBarcode(barcode) {
        const products = this.env.services.pos.records['product.product'] || {};
        const product = Object.values(products).find(
            p => p.barcode === barcode
        );

        if (product) {
            const order = this.env.services.pos.get_order();
            if (order) {
                order.add_product(product, { quantity: 1 });
            }
        }
        // Could also handle: partner barcode, coupon barcode, etc.
    },
});

/** @odoo-module alias=buz_pos_integration.PromptPayQR **/
import { ReceiptScreen } from "@point_of_sale/app/screens/receipt_screen/receipt_screen";
import { patch } from "@odoo/owl";

patch(ReceiptScreen.prototype, {
    /**
     * Generate PromptPay QR payload (EMVCo format).
     * Format: 00020101021229370016A000000677010111...
     */
    buzGeneratePromptPayQR(ppId, amount) {
        if (!ppId) return null;

        const idType = ppId.length >= 13 ? 'A' : 'M';
        let payload = '000201'; // Version
        payload += '010212'; // Point of Initiation (12 = dynamic)

        // Merchant Account Info (PromptPay)
        const merchantId = this._buzTLV('00', 'A000000677010111');
        const payeeId = this._buzTLV(
            idType === 'A' ? '02' : '01',
            ppId
        );
        const merchantAccount = this._buzTLV('29', merchantId + payeeId);
        payload += merchantAccount;

        payload += '5802TH'; // Country Code
        payload += this._buzTLV('54', amount.toFixed(2)); // Transaction Amount
        payload += '6304'; // CRC placeholder

        // Calculate CRC16
        const crc = this._buzCRC16(payload);
        payload += crc.toUpperCase();

        return payload;
    },

    _buzTLV(tag, value) {
        const len = value.length.toString().padStart(2, '0');
        return `${tag}${len}${value}`;
    },

    _buzCRC16(str) {
        let crc = 0xFFFF;
        for (let i = 0; i < str.length; i++) {
            crc ^= str.charCodeAt(i) << 8;
            for (let j = 0; j < 8; j++) {
                if (crc & 0x8000) {
                    crc = (crc << 1) ^ 0x1021;
                } else {
                    crc = crc << 1;
                }
            }
            crc &= 0xFFFF;
        }
        return crc.toString(16).padStart(4, '0');
    },
});

/** @odoo-module alias=buz_pos_integration.LINENotify **/
import { Component } from "@odoo/owl";

export class LINENotify {
    constructor(orm, config) {
        this.orm = orm;
        this.token = config.buz_line_notify_token;
    }

    async send(message) {
        if (!this.token) {
            console.warn('[Buz POS] LINE Notify: No token configured');
            return false;
        }

        try {
            // Send via backend to avoid CORS issues
            await this.orm.call(
                'pos.order',
                'action_buz_notify_delivery',
                [],
                { message },
            );
            return true;
        } catch (err) {
            console.error('[Buz POS] LINE Notify failed:', err);
            return false;
        }
    }
}

