from odoo import tests


@tests.tagged('post_install', '-at_install')
class TestBuzPromotion(tests.TransactionCase):

    def setUp(self):
        super().setUp()
        self.Rule = self.env['buz.promotion.rule']
        self.Coupon = self.env['buz.promotion.coupon']

    def test_create_discount_rule(self):
        rule = self.Rule.create({
            'name': 'Summer Sale 10%',
            'rule_type': 'discount_percent',
            'discount_percent': 10.0,
            'auto_apply': True,
            'min_order_amount': 500.0,
        })
        self.assertEqual(rule.rule_type, 'discount_percent')
        self.assertEqual(rule.discount_percent, 10.0)

    def test_create_coupon(self):
        rule = self.Rule.create({
            'name': 'Test Rule',
            'rule_type': 'discount_fixed',
            'discount_fixed_amount': 50.0,
        })
        coupon = self.Coupon.create({
            'rule_id': rule.id,
            'max_use': 3,
        })
        self.assertTrue(coupon.name.startswith('PROMO'))
        self.assertEqual(coupon.state, 'active')

    def test_coupon_usage(self):
        rule = self.Rule.create({
            'name': 'Test',
            'rule_type': 'discount_percent',
            'discount_percent': 5.0,
        })
        coupon = self.Coupon.create({
            'rule_id': rule.id,
            'max_use': 1,
        })
        coupon.action_use()
        self.assertEqual(coupon.use_count, 1)
        self.assertEqual(coupon.state, 'used')
